async (params, browser) => {
  // Open HF spaces search
  await browser.open(`https://huggingface.co/spaces?search=${params.query}`)

  // Wait for results
  await browser.waitForSelector('h4, article', 15000)

  // Let results render
  await browser.wait(2500)

  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract spaces
  const results = await browser.evaluate(`const results = []; const cards = document.querySelectorAll('article, main a[href]:has(h4)'); for (let i = 0; i < Math.min(cards.length, 15); i++) { const c = cards[i]; const titleEl = c.querySelector('h4'); if (!titleEl) continue; const link = c.closest('a[href]') || c.querySelector('a[href]') || c; const spans = Array.from(c.querySelectorAll('span')).map(s => s.textContent.trim()).filter(Boolean); results.push({ name: titleEl.textContent.trim(), url: link.href || '', meta: spans.slice(0, 5) }); } return { query: '' + params.query + '', result_count: results.length, results };`)

  return results
}
